import React, { useState } from 'react';

// Missing Button component-এর জন্য একটি ইনলাইন Button তৈরি করা হলো
const Button = ({ children, variant }) => {
  const baseStyle = "px-8 py-3 rounded-full font-semibold transition shadow-md";
  const variantStyle = variant === 'secondary'
    ? "bg-amber-600 hover:bg-amber-700 text-white"
    : "bg-white text-black hover:bg-gray-100";

  return (
    <button className={`${baseStyle} ${variantStyle}`}>
      {children}
    </button>
  );
};

